                <button disabled={!bio || !name || uploadingUserData} onClick={(e) => handleSubmit(e)} className={!bio || !name || uploadingUserData ? "save-bttn-disabled" : 'save-bttn'}>
                    {uploadingUserData ? 'Saving...' : 'Save'}
                </button>

            </motion.div>

        </div>
        )}
        </AnimatePresence>

        <div className="home-parent-container">
             <div className="side-bar-holder-container">
                <Sidebar links={links}/> {/*passing the setShowEditor to this component to be used as a state setter inside this component*/}
            </div>
